import React, { useEffect, useRef } from 'react';
import { createChart, CrosshairMode } from 'lightweight-charts';

export function PriceChart({ data, width = 0, height = 400 }) {
  const chartContainerRef = useRef();
  const chartRef = useRef();

  useEffect(() => {
    if (!chartContainerRef.current) return;

    // Initialize chart
    const chart = createChart(chartContainerRef.current, {
      width: chartContainerRef.current.clientWidth,
      height: height,
      layout: {
        background: { type: 'solid', color: 'transparent' },
        textColor: '#d1d5db',
      },
      grid: {
        vertLines: { color: 'rgba(42, 46, 57, 0.5)' },
        horzLines: { color: 'rgba(42, 46, 57, 0.5)' },
      },
      crosshair: { mode: CrosshairMode.Normal },
      rightPriceScale: { borderColor: 'rgba(197, 203, 206, 0.8)' },
      timeScale: { 
        borderColor: 'rgba(197, 203, 206, 0.8)',
        timeVisible: true,
      },
    });

    chartRef.current = chart;

    const candleSeries = chart.addCandlestickSeries({
      upColor: '#26a69a',
      downColor: '#ef5350',
      borderVisible: false,
      wickUpColor: '#26a69a',
      wickDownColor: '#ef5350',
    });

    // Formatting data for lightweight charts
    // Requirements: time (unix timestamp or strictly formatted string: '2019-04-11'), open, high, low, close
    if (data && data.length > 0) {
      const formattedData = data.map(c => {
         // lightweight-charts needs epoch timestamps (in seconds) or business days
         const dt = new Date(c.datetime.replace(' ', 'T') + 'Z');
         return {
            time: Math.floor(dt.getTime() / 1000), 
            open: c.open,
            high: c.high,
            low: c.low,
            close: c.close
         }
      });

      // Need to ensure unique timescale and sorted arrays
      const uniqueData = Array.from(new Map(formattedData.map(item => [item.time, item])).values());
      uniqueData.sort((a,b) => a.time - b.time);

      candleSeries.setData(uniqueData);
    }

    // Auto-resize handler
    const handleResize = () => {
      chart.applyOptions({ width: chartContainerRef.current.clientWidth });
    };

    window.addEventListener('resize', handleResize);

    return () => {
      window.removeEventListener('resize', handleResize);
      chart.remove();
    };
  }, [data, height]);

  return (
    <div className="w-full relative bg-card border border-border rounded-xl overflow-hidden shadow-md">
       <div className="absolute top-4 left-4 z-10 text-sm font-semibold tracking-wider opacity-80 backdrop-blur-sm bg-background/50 px-2 py-1 rounded">
         EUR/USD  &bull; H1
       </div>
       <div ref={chartContainerRef} className="w-full" />
    </div>
  );
}

import React from 'react';
import { Share2, Clock, AlertTriangle } from 'lucide-react';

export function SignalCard({ signalObject, currentPrice }) {
  if (!signalObject) {
    return (
       <div className="bg-card border border-border rounded-xl p-6 h-full flex flex-col items-center justify-center text-muted-foreground">
          <Clock className="w-12 h-12 mb-4 opacity-20" />
          <p>Awaiting Signal Generation...</p>
       </div>
    );
  }

  const { signal, confidence, timestamp, entry, stop_loss, take_profit_1, take_profit_2, top_reasons, invalidation } = signalObject;

  const getColors = () => {
    switch (signal) {
      case 'BUY': return { bg: 'bg-green-500/10', text: 'text-green-500', border: 'border-green-500/20' };
      case 'SELL': return { bg: 'bg-red-500/10', text: 'text-red-500', border: 'border-red-500/20' };
      default: return { bg: 'bg-yellow-500/10', text: 'text-yellow-500', border: 'border-yellow-500/20' };
    }
  };

  const colors = getColors();
  const timeStr = new Date(timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'});

  return (
    <div className={`bg-card border ${colors.border} rounded-xl p-6 relative overflow-hidden flex flex-col h-full shadow-lg`}>
      {/* Background glow sync'd to signal */}
      <div className={`absolute -top-24 -right-24 w-48 h-48 ${colors.bg} rounded-full blur-3xl opacity-50 pointer-events-none`} />

      <div className="flex justify-between items-start mb-6">
        <div>
          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-1">Master Signal</h2>
          <div className="flex items-center gap-3">
             <span className={`text-5xl font-extrabold tracking-tighter ${colors.text}`}>{signal}</span>
             <div className="flex flex-col">
                <span className="text-xl font-bold">{(confidence * 100).toFixed(0)}%</span>
                <span className="text-xs text-muted-foreground">Confidence</span>
             </div>
          </div>
        </div>
        <div className="text-right">
           <p className="text-sm text-muted-foreground">Generated at</p>
           <p className="font-mono text-lg">{timeStr}</p>
        </div>
      </div>

      {signal !== 'HOLD' ? (
        <div className="grid grid-cols-2 gap-4 mb-6">
          <div className="bg-muted/30 p-3 rounded-lg border border-border/50">
            <p className="text-xs text-muted-foreground mb-1 uppercase tracking-wider">Entry Price</p>
            <p className="font-mono font-medium text-lg">{entry?.toFixed(5)}</p>
          </div>
          <div className="bg-destructive/10 p-3 rounded-lg border border-destructive/20">
            <p className="text-xs text-destructive mb-1 uppercase tracking-wider">Stop Loss</p>
            <p className="font-mono font-medium text-lg text-destructive">{stop_loss?.toFixed(5)}</p>
          </div>
          <div className="bg-green-500/10 p-3 rounded-lg border border-green-500/20">
            <p className="text-xs text-green-500 mb-1 uppercase tracking-wider">Take Profit 1</p>
            <p className="font-mono font-medium text-lg text-green-500">{take_profit_1?.toFixed(5)}</p>
            <p className="text-[10px] text-green-600/70 mt-1">Reward 1:2</p>
          </div>
          <div className="bg-green-500/10 p-3 rounded-lg border border-green-500/20">
            <p className="text-xs text-green-500 mb-1 uppercase tracking-wider">Take Profit 2</p>
            <p className="font-mono font-medium text-lg text-green-500">{take_profit_2?.toFixed(5)}</p>
            <p className="text-[10px] text-green-600/70 mt-1">Reward 1:4</p>
          </div>
        </div>
      ) : (
        <div className="flex-1 flex items-center justify-center text-muted-foreground">
           Wait for valid technical momentum and model consensus.
        </div>
      )}

      {top_reasons && top_reasons.length > 0 && (
        <div className="mt-auto">
          <h3 className="text-sm font-semibold mb-2">Primary Factors:</h3>
          <ul className="space-y-1.5">
            {top_reasons.map((r, i) => (
              <li key={i} className="text-sm text-foreground/80 flex items-start">
                <span className="text-primary mr-2 mt-0.5">•</span>
                {r}
              </li>
            ))}
          </ul>
        </div>
      )}

      {invalidation && signal !== 'HOLD' && (
         <div className="mt-4 pt-4 border-t border-border/50 flex items-center text-xs text-muted-foreground">
            <AlertTriangle className="w-4 h-4 mr-2 text-yellow-500/70" />
            <span>{invalidation}</span>
         </div>
      )}
    </div>
  );
}

import * as tf from '@tensorflow/tfjs';

const FEATURES = [
  'log_return', 'rsi_norm', 'hl_range', 'body_size', 'macd_hist', 
  'bb_pct_b', 'bb_width', 'atr_norm', 'stoch_k', 'stoch_d', 
  'vol_ratio', 'hour_sin', 'hour_cos', 'dow_sin', 'dow_cos'
];
const LOOKBACK = 24; // H1 candles of features
const FEATURE_COUNT = FEATURES.length;
const MODEL_SAVE_PATH = 'indexeddb://eurusd-lstm-model';

export class LSTMModel {
  constructor() {
    this.name = 'LSTMModel';
    this.model = null;
    this.isTrained = false;
  }

  async loadModelFromDb() {
    try {
      this.model = await tf.loadLayersModel(MODEL_SAVE_PATH);
      // We must compile it after loading before using evaluating/training
      this.model.compile({
          optimizer: tf.train.adam(0.001),
          loss: 'binaryCrossentropy',
          metrics: ['accuracy']
      });
      this.isTrained = true;
      console.log("[LSTMModel] Loaded existing weights from IndexedDB.");
      return true;
    } catch (e) {
      console.log("[LSTMModel] No previous model found in DB, requires training.");
      return false;
    }
  }

  buildModel() {
    this.model = tf.sequential();

    // LSTM(64) -> Dropout(0.2)
    this.model.add(tf.layers.lstm({
      units: 64,
      returnSequences: true,
      inputShape: [LOOKBACK, FEATURE_COUNT]
    }));
    this.model.add(tf.layers.dropout({ rate: 0.2 }));

    // LSTM(32) -> Dropout(0.2)
    this.model.add(tf.layers.lstm({
      units: 32,
      returnSequences: false
    }));
    this.model.add(tf.layers.dropout({ rate: 0.2 }));

    // Dense(16) -> Dense(1)
    this.model.add(tf.layers.dense({ units: 16, activation: 'relu' }));
    this.model.add(tf.layers.dense({ units: 1, activation: 'sigmoid' }));

    this.model.compile({
      optimizer: tf.train.adam(0.001),
      loss: 'binaryCrossentropy',
      metrics: ['accuracy']
    });
  }

  prepareSequences(featuresArr) {
    const X = [];
    const y = [];

    // Filter nulls and convert to matrix
    const cleanRows = [];
    for (let i = 0; i < featuresArr.length; i++) {
        let hasNull = false;
        const rowData = [];
        for (const feat of FEATURES) {
            let val = featuresArr[i][feat];
            if (val === null || val === undefined || isNaN(val)) {
                hasNull = true; break;
            }
            rowData.push(val);
        }
        if (featuresArr[i].target_class === null) hasNull = true;

        if (!hasNull) {
            cleanRows.push({
                x: rowData,
                y: featuresArr[i].target_class
            });
        }
    }

    // create overlapping sequences
    for (let i = 0; i < cleanRows.length - LOOKBACK; i++) {
      const seqX = [];
      for (let j = 0; j < LOOKBACK; j++) {
         seqX.push(cleanRows[i + j].x);
      }
      X.push(seqX);
      // Target is the target of the last candle in the sequence
      y.push(cleanRows[i + LOOKBACK - 1].y);
    }

    return { X, y };
  }

  async train(featuresArr, onProgressCallback = (epoch, logs) => {}) {
    console.log("[LSTMModel] Starting training prep...");

    const {X, y} = this.prepareSequences(featuresArr);
    if (X.length < 100) {
       throw new Error("LSTM needs at least 100 valid sequences to train effectively.");
    }

    if (!this.model) {
      this.buildModel();
    }

    // Walk forward split - no shuffling time series!
    // Keras fit doesn't let us disable shuffling on validation split natively without manual splitting.
    // So we manually slice into Tensors.
    const splitIdx = Math.floor(X.length * 0.8);

    // Tidy up tensors after memory use
    let hist;

    await tf.tidy(() => {
        const xTrainT = tf.tensor3d(X.slice(0, splitIdx));
        const yTrainT = tf.tensor2d(y.slice(0, splitIdx), [splitIdx, 1]);

        const xValT = tf.tensor3d(X.slice(splitIdx));
        const yValT = tf.tensor2d(y.slice(splitIdx), [X.length - splitIdx, 1]);

        return this.model.fit(xTrainT, yTrainT, {
            epochs: 50,
            batchSize: 32,
            validationData: [xValT, yValT],
            shuffle: false, // critical for time series
            callbacks: {
              onEpochEnd: (epoch, logs) => {
                onProgressCallback(epoch, logs);
              }
            }
        });
    }).then(result => hist = result);

    console.log("[LSTMModel] Training complete.");
    this.isTrained = true;

    // Save model to DB
    await this.model.save(MODEL_SAVE_PATH);
    console.log("[LSTMModel] Weights saved to DB.");
  }

  predictSequence(recentFeatures) {
     if (!this.isTrained || !this.model || recentFeatures.length < LOOKBACK) {
         return { signal: 'HOLD', probability: 0.5 };
     }

     return tf.tidy(() => {
         const seqX = [];
         // grab the last `LOOKBACK` items
         const latestContext = recentFeatures.slice(-LOOKBACK);

         for (const row of latestContext) {
             const rowData = [];
             for (const feat of FEATURES) {
                 rowData.push(row[feat] || 0);
             }
             seqX.push(rowData);
         }

         const inputTensor = tf.tensor3d([seqX]); // Batch size of 1
         const predTensor = this.model.predict(inputTensor);
         const probability = predTensor.dataSync()[0];

         let signal = 'HOLD';
         if (probability > 0.62) signal = 'BUY';
         else if (probability < 0.38) signal = 'SELL';

         return { signal, probability };
     });
  }
}

import React, { useEffect, useState } from 'react';
import { useStore } from '@/store/useStore';
import { dataManager } from '@/services/DataManager';
import { PriceChart } from '@/components/dashboard/PriceChart';
import { RefreshCw } from 'lucide-react';

export default function ChartPage() {
  const [candles, setCandles] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const apiKey = useStore(state => state.apiKey);

  const fetchChartData = async () => {
    if (!apiKey) {
       setLoading(false);
       return;
    }
    setLoading(true);
    setError(null);
    try {
      const data = await dataManager.getCandles('EUR/USD', '1h', 500);
      setCandles(data.values);
    } catch (err) {
      console.error(err);
      setError("Failed to load chart data");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchChartData();
  }, [apiKey]);

  if (!apiKey) {
     return <div className="p-6">Requires API Key in Settings to view chart.</div>
  }

  return (
    <div className="flex flex-col h-full w-full">
      <div className="px-6 py-4 flex justify-between items-center border-b border-border shrink-0">
         <h1 className="text-xl font-bold">Interactive Chart</h1>
         <button 
           onClick={fetchChartData}
           disabled={loading}
           className="flex items-center gap-2 bg-secondary text-secondary-foreground hover:bg-secondary/80 px-4 py-2 rounded-md text-sm font-medium transition-colors disabled:opacity-50"
         >
           <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
           Refresh
         </button>
      </div>
      <div className="flex-1 min-h-0 p-6 relative">
          {error && <div className="absolute z-50 bg-destructive/90 text-destructive-foreground p-4 ml-4 mt-4 rounded">{error}</div>}
          <div className="h-full w-full grid">
             <PriceChart data={candles} height={window.innerHeight - 150} />
          </div>
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useStore } from '@/store/useStore';
import { dataManager } from '@/services/DataManager';
import { FeatureEngine } from '@/services/FeatureEngine';
import { signalAggregator } from '@/services/SignalAggregator';
import { Brain, Play, Save, RefreshCw } from 'lucide-react';

export default function ModelsPage() {
  const weights = useStore(state => state.modelWeights);
  const setModelWeights = useStore(state => state.setModelWeights);
  const apiKey = useStore(state => state.apiKey);

  const [trainingState, setTrainingState] = useState({
      isTraining: false,
      epoch: 0,
      loss: 0,
      accuracy: 0,
      message: 'Ready to train on latest cache.'
  });

  const [localWeights, setLocalWeights] = useState({ ...weights });

  const handleRetrainLSTM = async () => {
     if (!apiKey) return alert("API Key required to fetch data for training.");

     setTrainingState({ isTraining: true, epoch: 0, loss: 0, accuracy: 0, message: 'Fetching historical data...' });

     try {
       const data = await dataManager.getCandles('EUR/USD', '1h', 500); // We need at least 200+ for features
       const features = FeatureEngine.extractFeatures(data.values);

       setTrainingState(prev => ({ ...prev, message: 'Compiling TensorFlow layers...' }));

       // Pass a callback to the LSTM model's train function to update UI
       await signalAggregator.models.lstm.train(features, (epoch, logs) => {
           setTrainingState({
               isTraining: true,
               epoch: epoch + 1,
               loss: logs.loss || 0,
               accuracy: logs.acc || 0,
               message: `Training epoch ${epoch + 1}/50...`
           });
       });

       setTrainingState({ isTraining: false, epoch: 50, loss: 0, accuracy: 0, message: 'Training complete. Weights saved to IndexedDB.' });
     } catch (e) {
         setTrainingState({ isTraining: false, epoch: 0, loss: 0, accuracy: 0, message: `Training failed: ${e.message}` });
     }
  };

  const saveWeights = () => {
      // Normalize to sum to 1.0 safely
      const total = Object.values(localWeights).reduce((a,b) => a + Number(b), 0);
      if (total <= 0) return alert("Weights must sum > 0");

      const normalized = {
          ruleEngine: Number((localWeights.ruleEngine / total).toFixed(2)),
          logistic: Number((localWeights.logistic / total).toFixed(2)),
          randomForest: Number((localWeights.randomForest / total).toFixed(2)),
          lstm: 1.0 - Number((localWeights.ruleEngine / total).toFixed(2)) - Number((localWeights.logistic / total).toFixed(2)) - Number((localWeights.randomForest / total).toFixed(2))
      };

      setModelWeights(normalized);
      setLocalWeights(normalized);
  };

  return (
    <div className="p-6 max-w-5xl mx-auto space-y-6">
      <h1 className="text-2xl font-bold">Models & AI Pipeline</h1>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Retrain Panel */}
        <div className="bg-card border border-border p-6 rounded-xl shadow-sm">
           <div className="flex items-center gap-2 mb-4">
              <Brain className="text-primary w-5 h-5" />
              <h2 className="text-lg font-semibold">TensorFlow.js LSTM Serverless Training</h2>
           </div>

           <p className="text-sm text-muted-foreground mb-6">
              Sequences are trained directly in your browser. This model learns from the latest 500 H1 candles 
              and maps sequential Feature Matrices to identify trend continuations.
           </p>

           <div className="bg-muted/30 p-4 rounded-lg border border-border/50 mb-6">
              <div className="flex justify-between text-xs mb-1 font-mono">
                 <span className={`${trainingState.isTraining ? 'text-primary animate-pulse' : 'text-muted-foreground'}`}>
                    {trainingState.message}
                 </span>
                 {trainingState.isTraining && <span>Epoch {trainingState.epoch}/50</span>}
              </div>
              <div className="w-full bg-background rounded-full h-2 overflow-hidden mb-2">
                 <div className="bg-primary h-2 transition-all duration-300" style={{ width: `${(trainingState.epoch / 50) * 100}%` }}></div>
              </div>
              <div className="flex justify-between text-xs text-muted-foreground font-mono">
                <span>Loss: {trainingState.loss.toFixed(4)}</span>
                <span>Accuracy: {(trainingState.accuracy * 100).toFixed(1)}%</span>
              </div>
           </div>

           <button 
              onClick={handleRetrainLSTM}
              disabled={trainingState.isTraining}
              className="w-full flex justify-center items-center gap-2 bg-primary text-primary-foreground font-semibold py-2 rounded-md hover:bg-primary/90 transition-colors disabled:opacity-50"
           >
              {trainingState.isTraining ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Play className="w-4 h-4" />}
              {trainingState.isTraining ? 'Training Model...' : 'Trigger Walk-Forward Retrain'}
           </button>
        </div>

        {/* Ensemble Tuning Panel */}
        <div className="bg-card border border-border p-6 rounded-xl shadow-sm flex flex-col">
           <h2 className="text-lg font-semibold mb-4">Ensemble Voting Weights</h2>
           <p className="text-sm text-muted-foreground mb-6">
              Adjust the voting power of each individual model. The SignalAggregator uses these weights to formulate the master output probability.
           </p>

           <div className="space-y-4 flex-1">
             {Object.entries(localWeights).map(([key, value]) => (
                <div key={key}>
                   <div className="flex justify-between text-sm mb-1">
                      <span className="capitalize">{key.replace(/([A-Z])/g, ' $1').trim()}</span>
                      <span className="font-mono text-primary">{(value * 100).toFixed(0)}%</span>
                   </div>
                   <input 
                     type="range" 
                     min="0" max="1" step="0.05"
                     value={value}
                     onChange={(e) => setLocalWeights({...localWeights, [key]: parseFloat(e.target.value)})}
                     className="w-full h-2 bg-muted rounded-lg appearance-none cursor-pointer accent-primary"
                   />
                </div>
             ))}
           </div>

           <button 
              onClick={saveWeights}
              className="mt-6 w-full flex justify-center items-center gap-2 bg-secondary text-secondary-foreground font-semibold py-2 rounded-md hover:bg-secondary/90 transition-colors"
           >
              <Save className="w-4 h-4" /> Save Weights
           </button>
        </div>
      </div>
    </div>
  );
}

import { 
  rsi, 
  macd, 
  bollingerbands, 
  ema, 
  atr, 
  stochastic, 
  cci, 
  williamsr 
} from 'technicalindicators';

export class FeatureEngine {

  /**
   * Main entry point: Transform array of raw OHLCV candles into feature matrix
   * @param {Array} candles - Array of objects {datetime, open, high, low, close, volume} ordered oldest to newest
   * @returns {Array} Array of objects containing all computed features
   */
  static extractFeatures(candles) {
    if (!candles || candles.length < 200) {
      console.warn("FeatureEngine requires at least 200 candles for proper EMA200 calculation.");
    }

    // Ensure ascending chronological order for indicators
    const sorted = [...candles].sort((a, b) => new Date(a.datetime) - new Date(b.datetime));

    // Arrays for technical indicators calculation
    const closePrices = sorted.map(c => c.close);
    const highPrices = sorted.map(c => c.high);
    const lowPrices = sorted.map(c => c.low);
    const volumes = sorted.map(c => c.volume);

    // Compute technical indicators
    const rsi14 = rsi({ period: 14, values: closePrices });
    const macdData = macd({
      values: closePrices,
      fastPeriod: 12,
      slowPeriod: 26,
      signalPeriod: 9,
      SimpleMAOscillator: false,
      SimpleMASignal: false
    });

    const bb = bollingerbands({ period: 20, stdDev: 2, values: closePrices });
    const ema9 = ema({ period: 9, values: closePrices });
    const ema21 = ema({ period: 21, values: closePrices });
    const ema50 = ema({ period: 50, values: closePrices });
    const ema200 = ema({ period: 200, values: closePrices });

    const atr14 = atr({ high: highPrices, low: lowPrices, close: closePrices, period: 14 });
    const stochData = stochastic({ high: highPrices, low: lowPrices, close: closePrices, period: 14, signalPeriod: 3 });
    const cci20 = cci({ high: highPrices, low: lowPrices, close: closePrices, period: 20 });
    const wr14 = williamsr({ high: highPrices, low: lowPrices, close: closePrices, period: 14 });

    // Calculate rolling volume SMA (20 period) manually for the ratio
    const volSma20 = [];
    for (let i = 0; i < volumes.length; i++) {
        if (i < 19) {
            volSma20.push(null);
        } else {
            const sum = volumes.slice(i - 19, i + 1).reduce((a, b) => a + b, 0);
            volSma20.push(sum / 20);
        }
    }

    // Build feature matrix
    const features = [];

    for (let i = 0; i < sorted.length; i++) {
        const c = sorted[i];
        const prevC = i > 0 ? sorted[i - 1] : null;

        const row = {
           datetime: c.datetime,
           open: c.open,
           high: c.high,
           low: c.low,
           close: c.close,
           volume: c.volume,
        };

        // Price-Derived Features
        row.log_return = prevC ? Math.log(c.close / prevC.close) : 0;
        const range = c.high - c.low;
        row.hl_range = range !== 0 ? range / c.close : 0;
        row.body_size = range !== 0 ? Math.abs(c.close - c.open) / range : 0;
        row.upper_wick = range !== 0 ? (c.high - Math.max(c.open, c.close)) / range : 0;
        row.lower_wick = range !== 0 ? (Math.min(c.open, c.close) - c.low) / range : 0;

        // Alignment helper: indicators return arrays shorter than input by `period - 1`
        // We pad the beginning with nulls so the index aligns with `sorted`
        const padAlign = (arr, period) => {
            const padCount = sorted.length - arr.length;
            if (i < padCount) return null;
            return arr[i - padCount];
        };

        // Indicator assignment
        row.rsi = padAlign(rsi14, 14);
        row.rsi_norm = row.rsi !== null ? row.rsi / 100 : null; // [0,1]

        const m = padAlign(macdData, 26); // MACD slow period determines start
        row.macd_line = m ? m.MACD : null;
        row.macd_signal = m ? m.signal : null;
        row.macd_hist = m ? m.histogram : null;

        const b = padAlign(bb, 20);
        if (b && b.upper - b.lower !== 0) {
            row.bb_pct_b = (c.close - b.lower) / (b.upper - b.lower);
            row.bb_width = (b.upper - b.lower) / b.middle;
        } else {
            row.bb_pct_b = null;
            row.bb_width = null;
        }

        row.ema9 = padAlign(ema9, 9);
        row.ema21 = padAlign(ema21, 21);
        row.ema50 = padAlign(ema50, 50);
        row.ema200 = padAlign(ema200, 200);

        // Cross signals
        row.ema9_gt_21 = (row.ema9 && row.ema21) ? (row.ema9 > row.ema21 ? 1 : 0) : null;
        row.ema21_gt_50 = (row.ema21 && row.ema50) ? (row.ema21 > row.ema50 ? 1 : 0) : null;

        const a = padAlign(atr14, 14);
        row.atr = a;
        row.atr_norm = a ? a / c.close : null;

        const s = padAlign(stochData, 14);
        row.stoch_k = s ? s.k : null;
        row.stoch_d = s ? s.d : null;

        row.cci = padAlign(cci20, 20);
        row.williams_r = padAlign(wr14, 14);

        row.vol_ratio = volSma20[i] ? c.volume / volSma20[i] : null;

        // Time Features (Requires parsing datetime strings correctly based on interval)
        // Twelve Data 'datetime' format: "2026-03-09 15:00:00"
        const dt = new Date(c.datetime.replace(' ', 'T') + 'Z'); // Parse as UTC assuming API returns UTC/EST. TwelveData is EST by default unless specified.
        // Assuming we standardized API to UTC time in application or treat Twelve Data string natively
        const hour = dt.getUTCHours();
        const dow = dt.getUTCDay(); // 0(Sun) - 6(Sat)

        row.hour_sin = Math.sin(2 * Math.PI * hour / 24);
        row.hour_cos = Math.cos(2 * Math.PI * hour / 24);

        // Trading week is 5 days, shift dow to 0-4 (Mon-Fri) if we ignore weekend gaps
        let adjustedDow = dow - 1; 
        if (adjustedDow < 0) adjustedDow = 4; // Map Sunday to Friday for continuous calc
        row.dow_sin = Math.sin(2 * Math.PI * adjustedDow / 5);
        row.dow_cos = Math.cos(2 * Math.PI * adjustedDow / 5);

        row.is_london = (hour >= 7 && hour < 16) ? 1 : 0;
        row.is_ny = (hour >= 13 && hour < 22) ? 1 : 0;
        row.is_overlap = (hour >= 13 && hour < 16) ? 1 : 0;

        features.push(row);
    }

    // Pass 2: Calculate Lag Features and Targets
    for (let i = 0; i < features.length; i++) {
        const row = features[i];

        // Lags
        row.return_lag1 = i >= 1 ? features[i-1].log_return : null;
        row.return_lag2 = i >= 2 ? features[i-2].log_return : null;
        row.return_lag3 = i >= 3 ? features[i-3].log_return : null;
        row.return_lag5 = i >= 5 ? features[i-5].log_return : null;

        row.rsi_lag1 = i >= 1 ? features[i-1].rsi_norm : null;
        row.rsi_lag3 = i >= 3 ? features[i-3].rsi_norm : null;

        row.macd_hist_lag1 = i >= 1 ? features[i-1].macd_hist : null;
        row.macd_hist_lag2 = i >= 2 ? features[i-2].macd_hist : null;

        // Targets (for historical training)
        // 1 if NEXT candle's close is higher than CURRENT close
        row.target_class = (i + 1 < features.length && features[i+1].close > row.close) ? 1 : 0;
        // Target specifically for the last row is unknown.
        if (i === features.length - 1) row.target_class = null; 

        row.forward_return_1 = (i + 1 < features.length) ? (features[i+1].close - row.close) / row.close : null;
        row.forward_return_3 = (i + 3 < features.length) ? (features[i+3].close - row.close) / row.close : null;
    }

    return features;
  }
}
